My Soultion for Job Scheduler in C#

using System;
using System.Collections.Generic;
using System.Timers;
using System.Threading;
using System.Collections.Concurrent;



public class Program
{
    public static void Main(string[] args)
    {
        Scheduler scheduler = new Scheduler();

        for (int i = 0; i < 10; i++)
        {
            var thread = new Thread(() => scheduler.Schedule(Function, i.ToString(), DateTime.Now.AddSeconds(5), DateTime.Now.AddDays(14), new TimeSpan(0, 0, 5), false));
            thread.Start();
        }

        scheduler.Schedule(Function, "1123", DateTime.Now.AddSeconds(5), DateTime.Now.AddDays(14), new TimeSpan(0, 0, 5), true);

        Console.ReadKey();
    }

    public static void Function(Task task)
    {
        Console.WriteLine($"Test function: {task.ID}");
    }
}

public class Scheduler
{
    private List<Task> tasks = new List<Task>();
    private object baton = new object();
    public Scheduler() {

    }

    public void Schedule(Action<Task> action, string id, DateTime start, DateTime end, TimeSpan interval, bool recurring) {
        lock(baton) {
            tasks.Add(new Task(this, action, id, start, end, interval, recurring));
        }
    }

    public void UnSchedule(Task t) {
        lock(baton) {
            foreach (var task in tasks) {
                if (task.ID == t.ID) {
                    t.Dispose();
                    tasks.Remove(t);
                    break;
                }
            }
        }
    }
}

public class Task : IDisposable
{
    private Scheduler _scheduler;
    private Action<Task> _action;
    private string _id;
    public string ID
    {
        get { return _id; }
        set { _id = value; }
    }
    private bool _recurring = false;
    private DateTime _start;
    private DateTime _end;
    private TimeSpan _interval;
    private System.Timers.Timer _timer;
    private DateTime _next;

    public Task(Scheduler scheduler, Action<Task> action, string id, DateTime start, DateTime end, TimeSpan interval, bool recurring)
    {
        _scheduler = scheduler;
        _recurring = recurring;
        _action = action;
        _id = id;
        _start = start;
        _end = end;
        _interval = interval;
        Init();
    }

    public void Init()
    {
        _next = DateTime.Now + _interval;
        _timer = new System.Timers.Timer((this._start - DateTime.Now).TotalMilliseconds);
        _timer.Elapsed += new ElapsedEventHandler(Elapsed);
        _timer.Start();
    }

    public void Elapsed(object sender, ElapsedEventArgs args)
    {
        if (!Ready())
        {
            return;
        }

        Run();
    }

    public bool Ready()
    {
        return DateTime.Now >= _next;
    }

    public void Run()
    {
        _action(this);

        if (Expired() || !this._recurring)
        {
            _scheduler.UnSchedule(this);
        }
    }

    public void Dispose() {
        _timer.Dispose();
        _timer = null;
    }

    public bool Expired()
    {
        if (DateTime.Now >= this._end)
        {
            return true;
        }

        return false;
    }
}
